import { readdirSync, readFileSync, statSync, writeFileSync } from 'node:fs'
import path from 'node:path'
import process from 'node:process'

const cwd = process.cwd()
const srcRoot = path.join(cwd, 'src')
const outputFile = path.join(srcRoot, 'shared/ui/icon-paths.ts')
const sourceRoot = resolveIconSource()
const iconNames = collectIconNames(srcRoot)

if (!iconNames.length) {
  throw new Error('No remixicon names found under src/.')
}

const entries = iconNames.map((name) => [name, readIconPaths(name)])
const fileContent = [
  '// Generated by scripts/sync-remix-icons.mjs',
  `// Source: ${sourceRoot}`,
  'export const ICON_PATHS: Record<string, string[]> = {',
  ...entries.map(([name, paths]) => `  '${name}': ${JSON.stringify(paths)},`),
  '}',
  '',
].join('\n')

writeFileSync(outputFile, fileContent, 'utf8')
console.log(`Synced ${entries.length} remix icons to ${path.relative(cwd, outputFile)}`)

function resolveIconSource() {
  const candidates = [
    process.env.REMIXICON_SOURCE,
    path.join(cwd, 'node_modules/remixicon/icons'),
    path.join(cwd, '../buildguard/node_modules/remixicon/icons'),
  ].filter(Boolean)

  for (const candidate of candidates) {
    if (candidate && existsDir(candidate)) {
      return candidate
    }
  }

  throw new Error(
    'Unable to find remixicon SVG source. Set REMIXICON_SOURCE or install remixicon locally.',
  )
}

function existsDir(target) {
  try {
    return statSync(target).isDirectory()
  } catch {
    return false
  }
}

function collectIconNames(root) {
  const names = new Set()
  walkFiles(root, (filePath) => {
    if (filePath === outputFile) return
    if (!/\.(vue|ts|js|tsx|jsx)$/.test(filePath)) return
    const content = readFileSync(filePath, 'utf8')
    const matches = content.match(/ri-[a-z0-9-]+/g)
    if (!matches) return
    for (const match of matches) {
      names.add(match)
    }
  })
  return [...names].sort()
}

function walkFiles(root, visitor) {
  for (const entry of readdirSync(root, { withFileTypes: true })) {
    const entryPath = path.join(root, entry.name)
    if (entry.isDirectory()) {
      walkFiles(entryPath, visitor)
      continue
    }
    visitor(entryPath)
  }
}

function readIconPaths(name) {
  const iconFileName = `${name.slice(3)}.svg`
  const svgFile = findIconFile(sourceRoot, iconFileName)
  if (!svgFile) {
    throw new Error(`Missing remixicon SVG for ${name}`)
  }
  const svg = readFileSync(svgFile, 'utf8')
  const paths = [...svg.matchAll(/<path[^>]*\sd="([^"]+)"/g)].map((match) => match[1])
  if (!paths.length) {
    throw new Error(`No <path d="..."> entries found in ${svgFile}`)
  }
  return paths
}

function findIconFile(root, fileName) {
  for (const entry of readdirSync(root, { withFileTypes: true })) {
    const entryPath = path.join(root, entry.name)
    if (entry.isDirectory()) {
      const found = findIconFile(entryPath, fileName)
      if (found) return found
      continue
    }
    if (entry.name === fileName) return entryPath
  }
  return null
}
